"""Pluggable authentication backends and helpers."""
from __future__ import annotations

import hashlib
import time
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Any, Callable

from vaultkey.access.tokens import Token, TokenStore
from vaultkey.crypto.random import constant_time_compare, generate_id, generate_salt, generate_token
from vaultkey.utils.errors import AuthenticationError, TokenError


DEFAULT_AUTH_TTL = 3600.0
DEFAULT_HASH_ITERATIONS = 120_000


def _now() -> float:
    return time.time()


def _require(value: str | None, name: str) -> str:
    if value is None or value == "":
        raise AuthenticationError(f"missing {name}", details={"field": name})
    return value


def _hash_secret(secret: str, salt: bytes, iterations: int) -> bytes:
    return hashlib.pbkdf2_hmac("sha256", secret.encode("utf-8"), salt, iterations, dklen=32)


def _normalize_fingerprint(fingerprint: str) -> str:
    return fingerprint.replace(":", "").replace(" ", "").lower()


def certificate_fingerprint(certificate: bytes | str) -> str:
    """Return a SHA-256 fingerprint for certificate-like bytes."""
    data = certificate.encode("utf-8") if isinstance(certificate, str) else certificate
    return hashlib.sha256(data).hexdigest()


@dataclass
class AuthResult:
    """A successful authentication result."""

    backend: str
    subject: str
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = DEFAULT_AUTH_TTL
    renewable: bool = True
    entity_id: str | None = None
    token_id: str | None = None
    accessor: str | None = None
    issued_at: float = field(default_factory=_now)

    @property
    def expire_time(self) -> float:
        if self.ttl <= 0:
            return 0.0
        return self.issued_at + self.ttl

    def to_dict(self) -> dict[str, Any]:
        return {
            "backend": self.backend,
            "subject": self.subject,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "ttl": self.ttl,
            "renewable": self.renewable,
            "entity_id": self.entity_id,
            "token_id": self.token_id[:8] + "..." if self.token_id else None,
            "accessor": self.accessor,
            "expire_time": self.expire_time,
        }


class AuthBackend(ABC):
    """Common interface for authentication backends."""

    def __init__(self, name: str, *, enabled: bool = True) -> None:
        self.name = name
        self.enabled = enabled

    def enable(self) -> None:
        self.enabled = True

    def disable(self) -> None:
        self.enabled = False

    def _ensure_enabled(self) -> None:
        if not self.enabled:
            raise AuthenticationError("auth backend disabled", details={"backend": self.name})

    @abstractmethod
    def authenticate(self, **credentials: Any) -> AuthResult:
        """Authenticate credentials and return an auth result."""


@dataclass
class UserpassUser:
    """A username/password principal."""

    username: str
    password_hash: bytes
    salt: bytes
    hash_iterations: int = DEFAULT_HASH_ITERATIONS
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = DEFAULT_AUTH_TTL
    entity_id: str | None = None
    disabled: bool = False
    created_at: float = field(default_factory=_now)
    updated_at: float = field(default_factory=_now)

    def to_dict(self) -> dict[str, Any]:
        return {
            "username": self.username,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "ttl": self.ttl,
            "entity_id": self.entity_id,
            "disabled": self.disabled,
        }


class UserpassAuthBackend(AuthBackend):
    """Username/password authentication with salted password hashes."""

    def __init__(
        self,
        name: str = "userpass",
        *,
        enabled: bool = True,
        hash_iterations: int = DEFAULT_HASH_ITERATIONS,
    ) -> None:
        super().__init__(name, enabled=enabled)
        if hash_iterations < 1:
            raise ValueError("hash_iterations must be positive")
        self.hash_iterations = hash_iterations
        self._users: dict[str, UserpassUser] = {}

    def add_user(
        self,
        username: str,
        password: str,
        *,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = DEFAULT_AUTH_TTL,
        entity_id: str | None = None,
        disabled: bool = False,
    ) -> UserpassUser:
        username = _require(username, "username")
        password = _require(password, "password")
        salt = generate_salt(32)
        user = UserpassUser(
            username=username,
            password_hash=_hash_secret(password, salt, self.hash_iterations),
            salt=salt,
            hash_iterations=self.hash_iterations,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            entity_id=entity_id,
            disabled=disabled,
        )
        self._users[username] = user
        return user

    def update_password(self, username: str, password: str) -> None:
        user = self._users.get(_require(username, "username"))
        if user is None:
            raise AuthenticationError("unknown user", details={"username": username})
        password = _require(password, "password")
        salt = generate_salt(32)
        user.salt = salt
        user.password_hash = _hash_secret(password, salt, self.hash_iterations)
        user.hash_iterations = self.hash_iterations
        user.updated_at = _now()

    def get_user(self, username: str) -> UserpassUser | None:
        return self._users.get(username)

    def delete_user(self, username: str) -> bool:
        return self._users.pop(username, None) is not None

    def disable_user(self, username: str) -> None:
        user = self._users.get(username)
        if user is None:
            raise AuthenticationError("unknown user", details={"username": username})
        user.disabled = True
        user.updated_at = _now()

    def enable_user(self, username: str) -> None:
        user = self._users.get(username)
        if user is None:
            raise AuthenticationError("unknown user", details={"username": username})
        user.disabled = False
        user.updated_at = _now()

    def list_users(self) -> list[str]:
        return sorted(self._users)

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._ensure_enabled()
        username = _require(credentials.get("username"), "username")
        password = _require(credentials.get("password"), "password")
        user = self._users.get(username)
        if user is None:
            raise AuthenticationError("bad username or password")
        if user.disabled:
            raise AuthenticationError("user disabled", details={"username": username})

        candidate = _hash_secret(password, user.salt, user.hash_iterations)
        if not constant_time_compare(candidate, user.password_hash):
            raise AuthenticationError("bad username or password")

        return AuthResult(
            backend=self.name,
            subject=username,
            policies=list(user.policies),
            metadata=dict(user.metadata),
            ttl=user.ttl,
            entity_id=user.entity_id,
        )


@dataclass
class AppRoleSecretID:
    """A generated AppRole secret ID."""

    secret_id: str
    created_at: float = field(default_factory=_now)
    ttl: float = 0.0
    num_uses: int = 0
    uses_remaining: int = 0
    metadata: dict[str, str] = field(default_factory=dict)

    def __post_init__(self) -> None:
        if self.num_uses > 0 and self.uses_remaining == 0:
            self.uses_remaining = self.num_uses

    @property
    def is_expired(self) -> bool:
        return self.ttl > 0 and _now() >= self.created_at + self.ttl

    @property
    def is_valid(self) -> bool:
        if self.is_expired:
            return False
        return not (self.num_uses > 0 and self.uses_remaining <= 0)

    def use(self) -> None:
        if not self.is_valid:
            raise AuthenticationError("invalid secret_id")
        if self.num_uses > 0:
            self.uses_remaining -= 1

    def to_dict(self) -> dict[str, Any]:
        return {
            "secret_id": self.secret_id[:8] + "...",
            "ttl": self.ttl,
            "num_uses": self.num_uses,
            "uses_remaining": self.uses_remaining,
            "metadata": dict(self.metadata),
        }


