class AppRoleAuthBackend(AuthBackend):
    """AppRole authentication with generated role IDs and secret IDs."""

    def __init__(self, name: str = "approle", *, enabled: bool = True) -> None:
        super().__init__(name, enabled=enabled)
        self._roles: dict[str, AppRole] = {}
        self._role_id_index: dict[str, str] = {}

    def create_role(
        self,
        name: str,
        *,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = DEFAULT_AUTH_TTL,
        entity_id: str | None = None,
        role_id: str | None = None,
        disabled: bool = False,
    ) -> AppRole:
        name = _require(name, "name")
        if name in self._roles:
            raise AuthenticationError("role already exists", details={"role": name})
        role_id = role_id or generate_id("role", 24)
        if role_id in self._role_id_index:
            raise AuthenticationError("role_id already exists", details={"role_id": role_id})
        role = AppRole(
            name=name,
            role_id=role_id,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            entity_id=entity_id,
            disabled=disabled,
        )
        self._roles[name] = role
        self._role_id_index[role_id] = name
        return role

    def get_role(self, name: str) -> AppRole | None:
        return self._roles.get(name)

    def delete_role(self, name: str) -> bool:
        role = self._roles.pop(name, None)
        if role is None:
            return False
        self._role_id_index.pop(role.role_id, None)
        return True

    def disable_role(self, name: str) -> None:
        role = self._roles.get(name)
        if role is None:
            raise AuthenticationError("unknown role", details={"role": name})
        role.disabled = True
        role.updated_at = _now()

    def enable_role(self, name: str) -> None:
        role = self._roles.get(name)
        if role is None:
            raise AuthenticationError("unknown role", details={"role": name})
        role.disabled = False
        role.updated_at = _now()

    def list_roles(self) -> list[str]:
        return sorted(self._roles)

    def generate_secret_id(
        self,
        role_name: str,
        *,
        ttl: float = 0.0,
        num_uses: int = 0,
        metadata: dict[str, str] | None = None,
    ) -> AppRoleSecretID:
        role = self._roles.get(_require(role_name, "role_name"))
        if role is None:
            raise AuthenticationError("unknown role", details={"role": role_name})
        secret_id = generate_token(32)
        secret = AppRoleSecretID(
            secret_id=secret_id,
            ttl=ttl,
            num_uses=num_uses,
            metadata=dict(metadata or {}),
        )
        role.secret_ids[secret_id] = secret
        role.updated_at = _now()
        return secret

    def list_secret_ids(self, role_name: str) -> list[str]:
        role = self._roles.get(role_name)
        if role is None:
            raise AuthenticationError("unknown role", details={"role": role_name})
        return sorted(role.secret_ids)

    def tidy_secret_ids(self, role_name: str) -> int:
        role = self._roles.get(role_name)
        if role is None:
            raise AuthenticationError("unknown role", details={"role": role_name})
        expired = [sid for sid, secret in role.secret_ids.items() if not secret.is_valid]
        for sid in expired:
            role.secret_ids.pop(sid, None)
        return len(expired)

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._ensure_enabled()
        role_id = _require(credentials.get("role_id"), "role_id")
        secret_id = _require(credentials.get("secret_id"), "secret_id")
        role_name = self._role_id_index.get(role_id)
        if role_name is None:
            raise AuthenticationError("bad role_id or secret_id")
        role = self._roles[role_name]
        if role.disabled:
            raise AuthenticationError("role disabled", details={"role": role.name})

        secret = role.secret_ids.get(secret_id)
        if secret is None:
            raise AuthenticationError("bad role_id or secret_id")
        secret.use()

        metadata = dict(role.metadata)
        metadata.update(secret.metadata)
        metadata["role_name"] = role.name
        return AuthResult(
            backend=self.name,
            subject=role.name,
            policies=list(role.policies),
            metadata=metadata,
            ttl=role.ttl,
            entity_id=role.entity_id,
        )


