class CertificateAuthBackend(AuthBackend):
    """Authenticate certificates by SHA-256 fingerprint."""

    def __init__(self, name: str = "cert", *, enabled: bool = True) -> None:
        super().__init__(name, enabled=enabled)
        self._certificates: dict[str, CertificateRecord] = {}
        self._fingerprint_index: dict[str, str] = {}

    def add_certificate(
        self,
        name: str,
        *,
        fingerprint: str | None = None,
        certificate: bytes | str | None = None,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = DEFAULT_AUTH_TTL,
        entity_id: str | None = None,
        disabled: bool = False,
    ) -> CertificateRecord:
        name = _require(name, "name")
        if fingerprint is None:
            if certificate is None:
                raise AuthenticationError("missing fingerprint", details={"field": "fingerprint"})
            fingerprint = certificate_fingerprint(certificate)
        normalized = _normalize_fingerprint(_require(fingerprint, "fingerprint"))
        if normalized in self._fingerprint_index:
            raise AuthenticationError("fingerprint already exists", details={"fingerprint": normalized})
        record = CertificateRecord(
            name=name,
            fingerprint=normalized,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            entity_id=entity_id,
            disabled=disabled,
        )
        old = self._certificates.get(name)
        if old is not None:
            self._fingerprint_index.pop(old.fingerprint, None)
        self._certificates[name] = record
        self._fingerprint_index[normalized] = name
        return record

    def get_certificate(self, name: str) -> CertificateRecord | None:
        return self._certificates.get(name)

    def delete_certificate(self, name: str) -> bool:
        record = self._certificates.pop(name, None)
        if record is None:
            return False
        self._fingerprint_index.pop(record.fingerprint, None)
        return True

    def disable_certificate(self, name: str) -> None:
        record = self._certificates.get(name)
        if record is None:
            raise AuthenticationError("unknown certificate", details={"certificate": name})
        record.disabled = True
        record.updated_at = _now()

    def enable_certificate(self, name: str) -> None:
        record = self._certificates.get(name)
        if record is None:
            raise AuthenticationError("unknown certificate", details={"certificate": name})
        record.disabled = False
        record.updated_at = _now()

    def list_certificates(self) -> list[str]:
        return sorted(self._certificates)

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._ensure_enabled()
        fingerprint = credentials.get("fingerprint")
        certificate = credentials.get("certificate")
        if fingerprint is None:
            if certificate is None:
                raise AuthenticationError("missing fingerprint", details={"field": "fingerprint"})
            fingerprint = certificate_fingerprint(certificate)
        normalized = _normalize_fingerprint(_require(fingerprint, "fingerprint"))
        record_name = self._fingerprint_index.get(normalized)
        if record_name is None:
            raise AuthenticationError("bad certificate fingerprint")
        record = self._certificates[record_name]
        if record.disabled:
            raise AuthenticationError("certificate disabled", details={"certificate": record.name})
        if not constant_time_compare(normalized.encode("ascii"), record.fingerprint.encode("ascii")):
            raise AuthenticationError("bad certificate fingerprint")
        return AuthResult(
            backend=self.name,
            subject=record.name,
            policies=list(record.policies),
            metadata=dict(record.metadata),
            ttl=record.ttl,
            entity_id=record.entity_id,
        )


class TokenAuthBackend(AuthBackend):
    """Validate already-issued VaultKey tokens."""

    def __init__(self, token_store: TokenStore, name: str = "token", *, enabled: bool = True) -> None:
        super().__init__(name, enabled=enabled)
        self.token_store = token_store

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._ensure_enabled()
        token_id = credentials.get("token") or credentials.get("token_id")
        token_id = _require(token_id, "token")
        try:
            token = self.token_store.lookup(token_id)
            token.use()
        except TokenError as exc:
            raise AuthenticationError("bad token", details={"reason": exc.code}) from exc
        return _result_from_token(self.name, token)


def _result_from_token(backend_name: str, token: Token) -> AuthResult:
    subject = token.entity_id or token.accessor
    return AuthResult(
        backend=backend_name,
        subject=subject,
        policies=list(token.policies),
        metadata=dict(token.metadata),
        ttl=token.remaining_ttl,
        renewable=token.renewable,
        entity_id=token.entity_id,
        token_id=token.token_id,
        accessor=token.accessor,
    )


class AuthManager:
    """Register auth backends by name and dispatch authentication requests."""

    def __init__(self, backends: dict[str, AuthBackend] | None = None) -> None:
        self._backends: dict[str, AuthBackend] = {}
        for name, backend in (backends or {}).items():
            self.register_backend(name, backend)

    def register_backend(self, name: str, backend: AuthBackend) -> None:
        name = _require(name, "backend")
        self._backends[name] = backend

    def unregister_backend(self, name: str) -> bool:
        return self._backends.pop(name, None) is not None

    def get_backend(self, name: str) -> AuthBackend | None:
        return self._backends.get(name)

    def list_backends(self) -> list[str]:
        return sorted(self._backends)

    def enable_backend(self, name: str) -> None:
        backend = self._get_required_backend(name)
        backend.enable()

    def disable_backend(self, name: str) -> None:
        backend = self._get_required_backend(name)
        backend.disable()

    def authenticate(self, backend_name: str, **credentials: Any) -> AuthResult:
        backend = self._get_required_backend(backend_name)
        if not backend.enabled:
            raise AuthenticationError("auth backend disabled", details={"backend": backend_name})
        return backend.authenticate(**credentials)

    def _get_required_backend(self, name: str) -> AuthBackend:
        name = _require(name, "backend")
        backend = self._backends.get(name)
        if backend is None:
            raise AuthenticationError("unknown auth backend", details={"backend": name})
        return backend


