        }


class AuthRateLimiter:
    """In-memory rate limiter for authentication attempts."""

    def __init__(
        self,
        max_attempts: int = 5,
        window_seconds: float = 60.0,
        lockout_seconds: float = 0.0,
        *,
        clock: Callable[[], float] = _now,
    ) -> None:
        if max_attempts < 1:
            raise ValueError("max_attempts must be positive")
        if window_seconds <= 0:
            raise ValueError("window_seconds must be positive")
        if lockout_seconds < 0:
            raise ValueError("lockout_seconds must be non-negative")
        self.max_attempts = max_attempts
        self.window_seconds = window_seconds
        self.lockout_seconds = lockout_seconds
        self._clock = clock
        self._states: dict[str, RateLimitState] = {}

    def is_allowed(self, subject: str) -> bool:
        state = self._state(subject)
        self._cleanup(state)
        now = self._clock()
        if state.locked_until > now:
            return False
        return len(state.attempts) < self.max_attempts

    def record_attempt(self, subject: str, success: bool) -> bool:
        state = self._state(subject)
        self._cleanup(state)
        if success:
            self.reset(subject)
            return True
        now = self._clock()
        state.attempts.append(now)
        if len(state.attempts) >= self.max_attempts and self.lockout_seconds > 0:
            state.locked_until = now + self.lockout_seconds
        return self.is_allowed(subject)

    def reset(self, subject: str) -> None:
        self._states.pop(subject, None)

    def get_state(self, subject: str) -> RateLimitState:
        state = self._state(subject)
        self._cleanup(state)
        return RateLimitState(subject=state.subject, attempts=list(state.attempts), locked_until=state.locked_until)

    def list_subjects(self) -> list[str]:
        return sorted(self._states)

    def _state(self, subject: str) -> RateLimitState:
        subject = _require(subject, "subject")
        if subject not in self._states:
            self._states[subject] = RateLimitState(subject=subject)
        return self._states[subject]

    def _cleanup(self, state: RateLimitState) -> None:
        cutoff = self._clock() - self.window_seconds
        state.attempts = [ts for ts in state.attempts if ts > cutoff]
        if state.locked_until and state.locked_until <= self._clock():
            state.locked_until = 0.0


RateLimiter = AuthRateLimiter


@dataclass
class AuthSession:
    """An authenticated session."""

    session_id: str
    subject: str
    backend: str
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = DEFAULT_AUTH_TTL
    entity_id: str | None = None
    created_at: float = field(default_factory=_now)
    last_active: float = field(default_factory=_now)
    revoked: bool = False

    @property
    def expire_time(self) -> float:
        if self.ttl <= 0:
            return 0.0
        return self.created_at + self.ttl

    @property
    def is_expired(self) -> bool:
        return self.ttl > 0 and _now() >= self.expire_time

    @property
    def is_active(self) -> bool:
        return not self.revoked and not self.is_expired

    def remaining_ttl(self, now: float | None = None) -> float:
        if self.ttl <= 0:
            return float("inf")
        now = now if now is not None else _now()
        return max(0.0, self.expire_time - now)

    def touch(self, now: float | None = None) -> None:
        self.last_active = now if now is not None else _now()

    def revoke(self) -> None:
        self.revoked = True

    def to_dict(self) -> dict[str, Any]:
        return {
            "session_id": self.session_id,
            "subject": self.subject,
            "backend": self.backend,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "ttl": self.ttl,
            "entity_id": self.entity_id,
            "created_at": self.created_at,
            "last_active": self.last_active,
            "revoked": self.revoked,
            "expire_time": self.expire_time,
        }


class AuthSessionStore:
    """In-memory auth session tracker."""

    def __init__(self, *, clock: Callable[[], float] = _now) -> None:
        self._clock = clock
        self._sessions: dict[str, AuthSession] = {}

    def create_session(self, result: AuthResult, *, ttl: float | None = None) -> AuthSession:
        now = self._clock()
        session = AuthSession(
            session_id=generate_id("session", 24),
            subject=result.subject,
            backend=result.backend,
            policies=list(result.policies),
            metadata=dict(result.metadata),
            ttl=result.ttl if ttl is None else ttl,
            entity_id=result.entity_id,
            created_at=now,
            last_active=now,
        )
        self._sessions[session.session_id] = session
        return session

    def get_session(self, session_id: str) -> AuthSession | None:
        return self._sessions.get(session_id)

    def validate_session(self, session_id: str) -> AuthSession:
        session = self._sessions.get(_require(session_id, "session_id"))
        if session is None:
            raise AuthenticationError("unknown session", details={"session_id": session_id})
        if session.revoked:
            raise AuthenticationError("session revoked", details={"session_id": session_id})
        if session.ttl > 0 and self._clock() >= session.expire_time:
            raise AuthenticationError("session expired", details={"session_id": session_id})
        session.touch(self._clock())
        return session

    def revoke_session(self, session_id: str) -> bool:
        session = self._sessions.get(session_id)
        if session is None:
            return False
        session.revoke()
        return True

    def list_sessions(self) -> list[str]:
        return sorted(self._sessions)

    def tidy(self) -> int:
        to_remove = [
            sid
            for sid, session in self._sessions.items()
            if session.revoked or (session.ttl > 0 and self._clock() >= session.expire_time)
        ]
        for sid in to_remove:
            self._sessions.pop(sid, None)
        return len(to_remove)


SessionTracker = AuthSessionStore


@dataclass
class MFAChallenge:
    """A deterministic in-memory MFA challenge."""

    challenge_id: str
    subject: str
    method: str
    code: str
    code_hash: bytes
    salt: bytes
    hash_iterations: int = DEFAULT_HASH_ITERATIONS
    ttl: float = 300.0
    max_attempts: int = 3
    attempts: int = 0
    metadata: dict[str, str] = field(default_factory=dict)
    created_at: float = field(default_factory=_now)
    verified_at: float | None = None

    @property
    def is_expired(self) -> bool:
        return self.ttl > 0 and _now() >= self.created_at + self.ttl

    @property
    def is_verified(self) -> bool:
        return self.verified_at is not None

    def to_dict(self) -> dict[str, Any]:
        return {
            "challenge_id": self.challenge_id,
            "subject": self.subject,
            "method": self.method,
            "ttl": self.ttl,
            "max_attempts": self.max_attempts,
            "attempts": self.attempts,
            "metadata": dict(self.metadata),
            "created_at": self.created_at,
            "verified_at": self.verified_at,
        }


class MFAChallengeStore:
    """Issue and verify in-memory MFA challenges."""

    def __init__(
        self,
        *,
        default_ttl: float = 300.0,
        max_attempts: int = 3,
        hash_iterations: int = DEFAULT_HASH_ITERATIONS,
        clock: Callable[[], float] = _now,
    ) -> None:
        if default_ttl <= 0:
            raise ValueError("default_ttl must be positive")
        if max_attempts < 1:
            raise ValueError("max_attempts must be positive")
        if hash_iterations < 1:
            raise ValueError("hash_iterations must be positive")
        self.default_ttl = default_ttl
        self.max_attempts = max_attempts
        self.hash_iterations = hash_iterations
        self._clock = clock
        self._challenges: dict[str, MFAChallenge] = {}

    def create_challenge(
        self,
        subject: str,
        *,
        method: str = "totp",
        code: str | None = None,
        ttl: float | None = None,
        metadata: dict[str, str] | None = None,
    ) -> MFAChallenge:
        subject = _require(subject, "subject")
        code = code or generate_token(6)
        salt = generate_salt(16)
        now = self._clock()
        challenge = MFAChallenge(
            challenge_id=generate_id("mfa", 24),
            subject=subject,
            method=method,
            code=code,
            code_hash=_hash_secret(code, salt, self.hash_iterations),
            salt=salt,
            hash_iterations=self.hash_iterations,
            ttl=self.default_ttl if ttl is None else ttl,
            max_attempts=self.max_attempts,
            metadata=dict(metadata or {}),
            created_at=now,
        )
        self._challenges[challenge.challenge_id] = challenge
        return challenge

    def verify_challenge(self, challenge_id: str, code: str) -> bool:
        challenge = self._challenges.get(_require(challenge_id, "challenge_id"))
        if challenge is None:
            raise AuthenticationError("unknown mfa challenge", details={"challenge_id": challenge_id})
        if challenge.is_verified:
            return True
        if challenge.ttl > 0 and self._clock() >= challenge.created_at + challenge.ttl:
            raise AuthenticationError("mfa challenge expired", details={"challenge_id": challenge_id})
        if challenge.attempts >= challenge.max_attempts:
            raise AuthenticationError("mfa challenge exhausted", details={"challenge_id": challenge_id})
        code = _require(code, "code")
        challenge.attempts += 1
        candidate = _hash_secret(code, challenge.salt, challenge.hash_iterations)
        if not constant_time_compare(candidate, challenge.code_hash):
            raise AuthenticationError("bad mfa code", details={"challenge_id": challenge_id})
        challenge.verified_at = self._clock()
        return True

    def get_challenge(self, challenge_id: str) -> MFAChallenge | None:
        return self._challenges.get(challenge_id)

    def list_challenges(self) -> list[str]:
        return sorted(self._challenges)

    def tidy(self) -> int:
        to_remove = [
            cid
            for cid, challenge in self._challenges.items()
            if challenge.is_verified
            or (challenge.ttl > 0 and self._clock() >= challenge.created_at + challenge.ttl)
        ]
        for cid in to_remove:
            self._challenges.pop(cid, None)
        return len(to_remove)


