class AuthEventLogger:
    """Append-only in-memory auth event logger."""

    def __init__(self, *, clock: Callable[[], float] = _now) -> None:
        self._clock = clock
        self._events: list[AuthEvent] = []

    def record(
        self,
        event_type: str,
        backend: str,
        subject: str,
        success: bool,
        *,
        message: str = "",
        metadata: dict[str, str] | None = None,
    ) -> AuthEvent:
        event = AuthEvent(
            event_id=generate_id("auth_evt", 16),
            event_type=event_type,
            backend=backend,
            subject=subject,
            success=success,
            message=message,
            metadata=dict(metadata or {}),
            timestamp=self._clock(),
        )
        self._events.append(event)
        return event

    def log_success(
        self,
        backend: str,
        subject: str,
        *,
        event_type: str = "login",
        metadata: dict[str, str] | None = None,
    ) -> AuthEvent:
        return self.record(event_type, backend, subject, True, metadata=metadata)

    def log_failure(
        self,
        backend: str,
        subject: str,
        *,
        event_type: str = "login",
        message: str = "",
        metadata: dict[str, str] | None = None,
    ) -> AuthEvent:
        return self.record(event_type, backend, subject, False, message=message, metadata=metadata)

    def list_events(
        self,
        *,
        backend: str | None = None,
        subject: str | None = None,
        success: bool | None = None,
    ) -> list[AuthEvent]:
        events = self._events
        if backend is not None:
            events = [event for event in events if event.backend == backend]
        if subject is not None:
            events = [event for event in events if event.subject == subject]
        if success is not None:
            events = [event for event in events if event.success == success]
        return sorted(events, key=lambda event: (event.timestamp, event.event_id))

    def count(self) -> int:
        return len(self._events)

    def clear(self) -> None:
        self._events.clear()


@dataclass(frozen=True)
class AuthConfig:
    """Validated auth helper configuration."""

    enabled_backends: list[str] = field(default_factory=list)
    default_ttl: float = DEFAULT_AUTH_TTL
    max_ttl: float = 0.0
    rate_limit_attempts: int = 5
    rate_limit_window: float = 60.0
    session_ttl: float = DEFAULT_AUTH_TTL
    mfa_ttl: float = 300.0

    def to_dict(self) -> dict[str, Any]:
        return {
            "enabled_backends": list(self.enabled_backends),
            "default_ttl": self.default_ttl,
            "max_ttl": self.max_ttl,
            "rate_limit_attempts": self.rate_limit_attempts,
            "rate_limit_window": self.rate_limit_window,
            "session_ttl": self.session_ttl,
            "mfa_ttl": self.mfa_ttl,
        }


class AuthConfigValidator:
    """Validate auth configuration dictionaries."""

    def __init__(self, known_backends: set[str] | None = None) -> None:
        self.known_backends = set(known_backends or set())

    def validate(self, config: AuthConfig | dict[str, Any]) -> list[str]:
        values = config.to_dict() if isinstance(config, AuthConfig) else dict(config)
        errors: list[str] = []

        enabled = values.get("enabled_backends", [])
        if enabled is None:
            enabled = []
        if not isinstance(enabled, list) or not all(isinstance(name, str) for name in enabled):
            errors.append("enabled_backends must be a list of strings")
        else:
            for name in enabled:
                if not name:
                    errors.append("enabled_backends cannot include empty names")
                elif self.known_backends and name not in self.known_backends:
                    errors.append(f"unknown backend: {name}")

        self._validate_positive_number(values, "default_ttl", errors, allow_zero=True)
        self._validate_positive_number(values, "max_ttl", errors, allow_zero=True)
        self._validate_positive_number(values, "rate_limit_window", errors)
        self._validate_positive_number(values, "session_ttl", errors, allow_zero=True)
        self._validate_positive_number(values, "mfa_ttl", errors)

        attempts = values.get("rate_limit_attempts", 5)
        if not isinstance(attempts, int) or attempts < 1:
            errors.append("rate_limit_attempts must be a positive integer")

        default_ttl = values.get("default_ttl", DEFAULT_AUTH_TTL)
        max_ttl = values.get("max_ttl", 0.0)
        if isinstance(default_ttl, int | float) and isinstance(max_ttl, int | float):
            if max_ttl > 0 and default_ttl > max_ttl:
                errors.append("default_ttl must be less than or equal to max_ttl")

        return sorted(errors)

    def assert_valid(self, config: AuthConfig | dict[str, Any]) -> None:
        errors = self.validate(config)
        if errors:
            raise AuthenticationError("invalid auth configuration", details={"errors": errors})

    @staticmethod
    def _validate_positive_number(
        values: dict[str, Any],
        field_name: str,
        errors: list[str],
        *,
        allow_zero: bool = False,
    ) -> None:
        value = values.get(field_name)
        if value is None:
            return
        if not isinstance(value, int | float):
            errors.append(f"{field_name} must be a number")
            return
        if allow_zero:
            if value < 0:
                errors.append(f"{field_name} must be non-negative")
        elif value <= 0:
            errors.append(f"{field_name} must be positive")


def validate_auth_config(config: AuthConfig | dict[str, Any]) -> list[str]:
    """Validate an auth config with the default validator."""
    return AuthConfigValidator().validate(config)


